import gettext as gettext_mod
from jinja2 import Environment

class FakeTranslations:
    def gettext(self, s):
        return s.upper()
    def ngettext(self, s, p, n):
        return (s if n==1 else p).upper()
    def dgettext(self, domain, s):
        return f'[{domain}]{s.upper()}'
    def dngettext(self, domain, s, p, n):
        base = s if n==1 else p
        return f'[{domain}]{base.upper()}'

